(function () {
  "use strict";

  /* ── Email anti-spam ──────────────── */
  var u = 'hkala402'; var d = 'gmail' + '.' + 'com';
  var email = u + '@' + d; var mailto = 'mai' + 'lto:' + email;
  var emailIds = ['email-about','email-contact-val'];
  var hrefIds  = ['email-about','email-contact-link','email-footer-link'];
  emailIds.forEach(function(id){ var el=document.getElementById(id); if(el) el.textContent=email; });
  hrefIds.forEach(function(id){ var el=document.getElementById(id); if(el) el.href=mailto; });

  /* ── Typewriter ───────────────────── */
  var roles = ["AI QA Engineer","LLM Output Validator","Hallucination Hunter","RAG Pipeline Tester","Prompt Test Engineer","AI Safety Tester"];
  var tw = document.getElementById("typewriter");
  if (tw) {
    var ri=0,ci=0,del=false,pause=false;
    function loop(){
      var cur=roles[ri];
      del ? ci-- : ci++;
      tw.textContent=cur.slice(0,ci);
      if(!del&&ci===cur.length){ if(!pause){pause=true;setTimeout(function(){del=true;pause=false;loop();},2200);return;} }
      if(del&&ci===0){ del=false; ri=(ri+1)%roles.length; }
      setTimeout(loop, del?55:ci===0?300:90);
    }
    setTimeout(loop,800);
  }

  /* ── Nav scroll shrink ────────────── */
  var hdr=document.getElementById("site-header");
  if(hdr) window.addEventListener("scroll",function(){
    hdr.style.background=window.scrollY>40?"rgba(7,7,13,0.98)":"rgba(7,7,13,0.9)";
  },{passive:true});

  /* ── Mobile nav ───────────────────── */
  var tog=document.getElementById("navToggle"); var nav=document.getElementById("nav-links");
  if(tog&&nav){
    tog.addEventListener("click",function(){
      var o=nav.classList.toggle("is-open"); tog.classList.toggle("is-open",o);
      document.body.style.overflow=o?"hidden":"";
    });
    nav.querySelectorAll("a").forEach(function(a){
      a.addEventListener("click",function(){ nav.classList.remove("is-open"); tog.classList.remove("is-open"); document.body.style.overflow=""; });
    });
    document.addEventListener("click",function(e){
      if(!nav.contains(e.target)&&!tog.contains(e.target)){ nav.classList.remove("is-open"); tog.classList.remove("is-open"); document.body.style.overflow=""; }
    });
  }

  /* ── Active nav highlight ─────────── */
  var secs=document.querySelectorAll("section[id]"); var navAs=document.querySelectorAll(".nav-links a");
  if(secs.length&&navAs.length){
    var obs=new IntersectionObserver(function(entries){
      entries.forEach(function(e){ if(e.isIntersecting){ var id=e.target.id; navAs.forEach(function(a){ a.style.color=(a.getAttribute("href")||"").includes(id)?"var(--cyan)":""; }); } });
    },{rootMargin:"-40% 0px -55% 0px"});
    secs.forEach(function(s){obs.observe(s);});
  }

  /* ── Fade-in on scroll ────────────── */
  var fades=document.querySelectorAll(".skill-group,.project-card,.contact-link,.stat,.edu-card,.ach-card,.exp-card,.sys-card");
  if("IntersectionObserver"in window&&fades.length){
    fades.forEach(function(el){ el.style.opacity="0"; el.style.transform="translateY(22px)"; el.style.transition="opacity 0.5s ease,transform 0.5s ease"; });
    var fo=new IntersectionObserver(function(entries){
      entries.forEach(function(e,i){ if(e.isIntersecting){ setTimeout(function(){ e.target.style.opacity="1"; e.target.style.transform="translateY(0)"; },60*(i%6)); fo.unobserve(e.target); } });
    },{threshold:0.1});
    fades.forEach(function(el){fo.observe(el);});
  }

  /* ── Contact form ─────────────────── */
  var form=document.getElementById("contact-form");
  if(form){ form.addEventListener("submit",function(e){ e.preventDefault(); setTimeout(function(){ var s=document.getElementById("cf-success"); if(s)s.style.display="block"; form.reset(); },600); }); }

})();

/* ── Certificate Viewer ──────────────── */
function openCert() {
  var b64 = "";
  var bin=atob(b64), bytes=new Uint8Array(bin.length);
  for(var i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i);
  var url=URL.createObjectURL(new Blob([bytes],{type:"application/pdf"}));
  window.open(url,"_blank");
}

